class Solution:
    def maximumOr(self, nums, k):
        n = len(nums)
        best = 0
        arr = list(nums)
        def rec(vals, ops):
            nonlocal best
            if ops == 0:
                cur = 0
                for v in vals:
                    cur |= v
                if cur > best:
                    best = cur
                return
            for i in range(n):
                vals[i] *= 2
                rec(vals, ops - 1)
                vals[i] //= 2
        rec(arr, k)
        return best

