class Solution:
    def maximumOr(self, nums, k):
        n = len(nums)
        suffix = [0] * (n + 1)
        for i in range(n - 1, -1, -1):
            suffix[i] = suffix[i + 1] | nums[i]
        best = 0
        prefix = 0
        for i in range(n):
            cur = prefix | (nums[i] << k) | suffix[i + 1]
            if cur > best:
                best = cur
            prefix |= nums[i]
        return best

