var maximumOr = function(nums, k) {
    const n = nums.length;
    const suffix = new Array(n + 1).fill(0);
    for (let i = n - 1; i >= 0; i--) {
        suffix[i] = suffix[i + 1] | nums[i];
    }
    let best = 0n;
    let prefix = 0;
    for (let i = 0; i < n; i++) {
        const shifted = BigInt(nums[i]) << BigInt(k);
        const cur = BigInt(prefix) | shifted | BigInt(suffix[i + 1]);
        if (cur > best) best = cur;
        prefix |= nums[i];
    }
    return Number(best);
};
